let documentId;

try {
  // Case 1: Workflow Initiated
  const items = $('Workflow Initiated').all();
  if (items.length && items[0].json.document) {
    documentId = items[0].json.document;
  }
} catch (e) {
  // ignore
}

if (!documentId) {
  try {
    // Case 2: Chat message (JSON string)
    const chatInput = $('When chat message received').first().json.chatInput;
    const parsed = JSON.parse(chatInput);
    documentId = parsed[0].document;
  } catch (e) {
    // ignore
  }
}

if (!documentId) {
  throw new Error('Document ID not found in any input');
}

return [
  {
    json: {
      inputData: documentId
    }
  }
];

